{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a graph embedding/layout problem where colors are nodes and adjacency is the edge set. To maximize empty cells, we need to find the smallest possible footprint for each color while maintaining connectivity and adjacency.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to extract two pieces of information: 1. A list of all unique non-zero colors present. 2. An adjacency list representing which colors are adjacent to each other in the input grid. Ensure that connectivity is verified for each color group."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given a set of colors and their adjacency requirements, design a strategy to place these colors on a 50x50 grid using the minimum number of cells possible. The strategy must ensure that for every color, all its cells are connected (4-connectivity) and that two colors are adjacent in the grid if and only if they were adjacent in the input graph. Suggest a layout pattern, such as a snake-like path or a compact cluster, that minimizes the total number of non-zero cells used."
    }
  ],
  "synthesis_brief": "The parent will use the graph_analyzer's adjacency list to understand the topological constraints and the layout_optimizer's strategy to generate a valid, compact 50x50 grid that maximizes the number of zero cells."
}
```

